   288|async function probe(fetchImpl: FetchLike, url: string, init: RequestInit, timeoutMs = 8000): Promise<{ status: number | null; ok: boolean; bodySnippet: string }> {
   289|  const controller = new AbortController();
   290|  const timer = setTimeout(() => controller.abort(), timeoutMs);
   291|  try {
   292|    const response = await fetchImpl(url, { ...init, signal: controller.signal });
   293|    let bodySnippet = '';
   294|    try {
   295|      bodySnippet = (await response.text()).slice(0, 200);
   296|    } catch {
   297|      bodySnippet = '';
   298|    }
   299|    return { status: response.status, ok: response.ok, bodySnippet };
   300|  } catch (error) {
   301|    const message = error instanceof Error ? error.message : 'network error';
   302|    return { status: null, ok: false, bodySnippet: message };
   303|  } finally {
   304|    clearTimeout(timer);
   305|  }
