   745|/**
   746| * Reads one encrypted Owner Variable for backend runtime use without exposing it to API responses.
   747| */
   748|export async function getIVXOwnerVariableRuntimeValue(name: OwnerVariableName): Promise<string> {
   749|  const envValue = readEnv(name);
   750|  if (envValue) return envValue;
   751|  try {
   752|    const row = await getStoredRow(name);
   753|    if (!row) return '';
   754|    const decrypted = tryDecryptRowValue(row);
   755|    if (!decrypted) {
   756|      console.log('[IVXOwnerVariables] Runtime value bridge: decryption failed for all key candidates', {
   757|        name,
   758|        maskedPreview: row.masked_preview,
   759|      });
   760|      return '';
   761|    }
   762|    // Auto-reencrypt with the primary key if a fallback key was used (key rotation)
   763|    if (decrypted.keyIndex > 0) {
   764|      const plaintext = decrypted.plaintext.trim();
   765|      try {
   766|        await reencryptStoredRow(name, plaintext);
   767|        console.log('[IVXOwnerVariables] Runtime value bridge: re-encrypted stale-key row with primary key', {
   768|          name,
   769|          keyIndex: decrypted.keyIndex,
   770|        });
   771|      } catch (reencryptError) {
   772|        console.log('[IVXOwnerVariables] Runtime value bridge: re-encryption failed (returning decrypted value anyway)', {
   773|          name,
   774|          message: reencryptError instanceof Error ? sanitizeExternalErrorDetail(reencryptError.message) : 'unknown',
   775|        });
   776|      }
   777|      return plaintext;
   778|    }
   779|    return decrypted.plaintext.trim();
   780|  } catch (error) {
   781|    console.log('[IVXOwnerVariables] Runtime value bridge unavailable:', {
   782|      name,
   783|      message: error instanceof Error ? sanitizeExternalErrorDetail(error.message) : 'unknown',
   784|    });
   785|    return '';
   786|  }
   787|}
