   789|/**
   790| * Re-encrypt a stored row's plaintext value with the current primary encryption key.
   791| * Used when a fallback key candidate succeeded (key rotation recovery).
   792| */
   793|async function reencryptStoredRow(name: OwnerVariableName, plaintext: string): Promise<void> {
   794| const metadata = variableMetadataByName.get(name);
   795| if (!metadata) return;
   796| const encrypted = encryptValue(plaintext);
   797| const timestamp = nowIso();
   798| const row: OwnerVariableRow = {
   799|   name,
   800|   provider: metadata.provider,
